declare(strict_types=1);
require_once __DIR__.'/auth.php';perpus_session_start();define('SDS_PERPUSTAKAAN_APP',true);$root=dirname(__DIR__);require_once $root.'/db.php';require_once $root.'/config/perpus.php';require_once __DIR__.'/lib/XlsxLite.php';
sds_perpus_ensure_schema($conn);$perpusUser=perpus_require_login($conn);
$report=(string)($_GET['report']??'ringkasan');$allowed=['ringkasan','sirkulasi','koleksi','anggota','kunjungan','denda','reservasi','saran'];if(!in_array($report,$allowed,true)){http_response_code(400);exit('Jenis laporan tidak valid.');}$from=(string)($_GET['from']??date('Y-m-01'));$to=(string)($_GET['to']??date('Y-m-d'));if(!preg_match('/^\d{4}-\d{2}-\d{2}$/',$from))$from=date('Y-m-01');if(!preg_match('/^\d{4}-\d{2}-\d{2}$/',$to))$to=date('Y-m-d');if($from>$to)[$from,$to]=[$to,$from];
function xrows(mysqli $c,string $sql,string $types='',array $params=[]):array{$s=$c->prepare($sql);if(!$s)return[];if($types!=='')$s->bind_param($types,...$params);$s->execute();$a=[];$r=$s->get_result();while($x=$r->fetch_assoc())$a[]=$x;$s->close();return$a;}function xscalar(mysqli $c,string $sql,string $types='',array $params=[]){$s=$c->prepare($sql);if(!$s)return 0;if($types!=='')$s->bind_param($types,...$params);$s->execute();$v=$s->get_result()->fetch_row()[0]??0;$s->close();return$v;}
$school='Sekolah';$r=$conn->query('SELECT nama_sekolah FROM pengaturan LIMIT 1');if($r&&($x=$r->fetch_assoc()))$school=(string)$x['nama_sekolah'];$period='Periode '.date('d/m/Y',strtotime($from)).'–'.date('d/m/Y',strtotime($to));
$metrics=[['Item Dipinjam',(int)xscalar($conn,'SELECT COUNT(*) FROM perpus_peminjaman_detail d JOIN perpus_peminjaman p ON p.id=d.peminjaman_id WHERE p.tanggal_pinjam BETWEEN ? AND ?','ss',[$from,$to])],['Pengembalian',(int)xscalar($conn,"SELECT COUNT(*) FROM perpus_peminjaman_detail WHERE DATE(tanggal_kembali) BETWEEN ? AND ? AND status<>'dipinjam'",'ss',[$from,$to])],['Kunjungan',(int)xscalar($conn,'SELECT COUNT(*) FROM perpus_kunjungan WHERE DATE(waktu_kunjungan) BETWEEN ? AND ?','ss',[$from,$to])],['Terlambat Saat Ini',(int)xscalar($conn,"SELECT COUNT(*) FROM perpus_peminjaman_detail WHERE status='dipinjam' AND tanggal_jatuh_tempo<CURDATE()")],['Denda Tercatat',(float)xscalar($conn,'SELECT COALESCE(SUM(denda),0) FROM perpus_peminjaman_detail WHERE DATE(tanggal_kembali) BETWEEN ? AND ?','ss',[$from,$to])],['Denda Dibayar/Disesuaikan',(float)xscalar($conn,'SELECT COALESCE(SUM(nominal),0) FROM perpus_denda_pembayaran WHERE DATE(created_at) BETWEEN ? AND ?','ss',[$from,$to])],['Reservasi',(int)xscalar($conn,'SELECT COUNT(*) FROM perpus_reservasi WHERE DATE(tanggal_reservasi) BETWEEN ? AND ?','ss',[$from,$to])],['Kritik & Saran',(int)xscalar($conn,'SELECT COUNT(*) FROM perpus_saran WHERE DATE(created_at) BETWEEN ? AND ?','ss',[$from,$to])]];
$sheets=[['name'=>'RINGKASAN','title'=>'RINGKASAN LAPORAN PERPUSTAKAAN','subtitle'=>$school.' · '.$period.' · Diekspor '.date('d/m/Y H:i'),'headers'=>['Indikator','Nilai'],'rows'=>$metrics,'widths'=>[34,22],'text_columns'=>[]]];
$headers=[];$rows=[];$widths=[];$text=[];$title='';
if($report==='ringkasan'){$title='AKTIVITAS HARIAN';$headers=['Tanggal','Item Dipinjam','Kunjungan'];$widths=[18,18,18];$data=xrows($conn,"SELECT tanggal,SUM(pinjam) pinjam,SUM(kunjung) kunjung FROM (SELECT p.tanggal_pinjam tanggal,COUNT(d.id) pinjam,0 kunjung FROM perpus_peminjaman p JOIN perpus_peminjaman_detail d ON d.peminjaman_id=p.id WHERE p.tanggal_pinjam BETWEEN ? AND ? GROUP BY p.tanggal_pinjam UNION ALL SELECT DATE(k.waktu_kunjungan),0,COUNT(*) FROM perpus_kunjungan k WHERE DATE(k.waktu_kunjungan) BETWEEN ? AND ? GROUP BY DATE(k.waktu_kunjungan)) x GROUP BY tanggal ORDER BY tanggal",'ssss',[$from,$to,$from,$to]);foreach($data as $x)$rows[]=[$x['tanggal'],(int)$x['pinjam'],(int)$x['kunjung']];}
elseif($report==='sirkulasi'){$title='LAPORAN SIRKULASI';$headers=['Tanggal Pinjam','Nomor Anggota','Nama','Unit/Rombel','Judul','Barcode','Jatuh Tempo','Tanggal Kembali','Status','Kondisi','Denda','Status Denda'];$widths=[18,20,30,24,38,20,18,20,16,16,18,18];$text=[1,5];$data=xrows($conn,"SELECT p.tanggal_pinjam,d.*,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,b.judul,e.barcode FROM perpus_peminjaman_detail d JOIN perpus_peminjaman p ON p.id=d.peminjaman_id JOIN perpus_anggota a ON a.id=p.anggota_id LEFT JOIN perpus_buku b ON b.id=d.buku_id LEFT JOIN perpus_buku_eksemplar e ON e.id=d.eksemplar_id WHERE p.tanggal_pinjam BETWEEN ? AND ? ORDER BY p.tanggal_pinjam DESC,d.id DESC",'ss',[$from,$to]);foreach($data as $x){$p=sds_perpus_identity_profile($conn,(string)$x['pemilik_tipe'],(int)($x['pemilik_id']??0),$x);$rows[]=[$x['tanggal_pinjam'],$x['nomor_anggota'],$p['nama'],$p['unit'],$x['judul'],$x['barcode'],$x['tanggal_jatuh_tempo'],$x['tanggal_kembali'],$x['status'],$x['kondisi_kembali'],(float)$x['denda'],$x['denda_status']];}}
elseif($report==='koleksi'){$title='LAPORAN KOLEKSI';$headers=['ID','Judul','ISBN','Tahun','Kategori','Tipe','Total Eksemplar','Tersedia','Dipinjam','Rusak','Hilang','Pemakaian Periode'];$widths=[12,38,20,12,22,20,18,15,15,15,15,20];$text=[2];$data=xrows($conn,"SELECT b.id,b.judul,b.isbn,b.tahun_terbit,k.nama kategori,t.nama tipe,COUNT(e.id) eksemplar,COALESCE(SUM(e.status='tersedia'),0) tersedia,COALESCE(SUM(e.status='dipinjam'),0) dipinjam,COALESCE(SUM(e.status='rusak'),0) rusak,COALESCE(SUM(e.status='hilang'),0) hilang,COALESCE((SELECT COUNT(*) FROM perpus_peminjaman_detail d JOIN perpus_peminjaman p ON p.id=d.peminjaman_id WHERE d.buku_id=b.id AND p.tanggal_pinjam BETWEEN ? AND ?),0) pemakaian FROM perpus_buku b LEFT JOIN perpus_kategori_buku k ON k.id=b.kategori_id LEFT JOIN perpus_tipe_koleksi t ON t.id=b.tipe_koleksi_id LEFT JOIN perpus_buku_eksemplar e ON e.buku_id=b.id AND e.status<>'nonaktif' GROUP BY b.id,b.judul,b.isbn,b.tahun_terbit,k.nama,t.nama ORDER BY pemakaian DESC,b.judul",'ss',[$from,$to]);foreach($data as $x)$rows[]=[(int)$x['id'],$x['judul'],$x['isbn'],$x['tahun_terbit'],$x['kategori'],$x['tipe'],(int)$x['eksemplar'],(int)$x['tersedia'],(int)$x['dipinjam'],(int)$x['rusak'],(int)$x['hilang'],(int)$x['pemakaian']];}
elseif($report==='anggota'){$title='LAPORAN ANGGOTA';$headers=['Nomor Anggota','Nama','Jenis','Unit/Rombel','Tipe Member','Status','Pinjaman Periode','Masih Aktif','Terlambat','Kunjungan'];$widths=[20,30,16,24,20,18,20,16,16,16];$text=[0];$data=xrows($conn,"SELECT a.*,tm.nama tipe_member,(SELECT COUNT(d.id) FROM perpus_peminjaman p JOIN perpus_peminjaman_detail d ON d.peminjaman_id=p.id WHERE p.anggota_id=a.id AND p.tanggal_pinjam BETWEEN ? AND ?) jumlah_pinjam,(SELECT COUNT(d.id) FROM perpus_peminjaman p JOIN perpus_peminjaman_detail d ON d.peminjaman_id=p.id WHERE p.anggota_id=a.id AND d.status='dipinjam') aktif,(SELECT COUNT(d.id) FROM perpus_peminjaman p JOIN perpus_peminjaman_detail d ON d.peminjaman_id=p.id WHERE p.anggota_id=a.id AND d.status='dipinjam' AND d.tanggal_jatuh_tempo<CURDATE()) terlambat,(SELECT COUNT(k.id) FROM perpus_kunjungan k WHERE k.anggota_id=a.id AND DATE(k.waktu_kunjungan) BETWEEN ? AND ?) kunjungan FROM perpus_anggota a LEFT JOIN perpus_tipe_member tm ON tm.id=a.tipe_member_id ORDER BY jumlah_pinjam DESC,kunjungan DESC",'ssss',[$from,$to,$from,$to]);foreach($data as $x){$p=sds_perpus_identity_profile($conn,(string)$x['pemilik_tipe'],(int)($x['pemilik_id']??0),$x);$rows[]=[$x['nomor_anggota'],$p['nama'],ucfirst((string)$x['pemilik_tipe']),$p['unit'],$x['tipe_member'],ucfirst((string)$x['status_keanggotaan']),(int)$x['jumlah_pinjam'],(int)$x['aktif'],(int)$x['terlambat'],(int)$x['kunjungan']];}}
elseif($report==='kunjungan'){$title='LAPORAN KUNJUNGAN';$headers=['Waktu','Nomor Anggota','Nama','Jenis','Unit/Rombel','Sumber'];$widths=[22,20,30,16,24,16];$text=[1];$data=xrows($conn,"SELECT k.*,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan FROM perpus_kunjungan k JOIN perpus_anggota a ON a.id=k.anggota_id WHERE DATE(k.waktu_kunjungan) BETWEEN ? AND ? ORDER BY k.waktu_kunjungan DESC",'ss',[$from,$to]);foreach($data as $x){$p=sds_perpus_identity_profile($conn,(string)$x['pemilik_tipe'],(int)($x['pemilik_id']??0),$x);$rows[]=[$x['waktu_kunjungan'],$x['nomor_anggota'],$p['nama'],ucfirst((string)$x['pemilik_tipe']),$p['unit'],ucfirst((string)$x['sumber'])];}}
elseif($report==='denda'){$title='LAPORAN DENDA';$headers=['Nomor Anggota','Nama','Unit/Rombel','Judul','Tanggal Kembali','Denda','Diselesaikan','Sisa','Status'];$widths=[20,30,24,38,20,18,18,18,18];$text=[0];$data=xrows($conn,"SELECT d.id,d.tanggal_kembali,d.denda,d.denda_status,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,b.judul,COALESCE(SUM(x.nominal),0) diselesaikan FROM perpus_peminjaman_detail d JOIN perpus_peminjaman p ON p.id=d.peminjaman_id JOIN perpus_anggota a ON a.id=p.anggota_id LEFT JOIN perpus_buku b ON b.id=d.buku_id LEFT JOIN perpus_denda_pembayaran x ON x.detail_id=d.id WHERE d.denda>0 AND DATE(d.tanggal_kembali) BETWEEN ? AND ? GROUP BY d.id,d.tanggal_kembali,d.denda,d.denda_status,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,b.judul ORDER BY d.tanggal_kembali DESC",'ss',[$from,$to]);foreach($data as $x){$p=sds_perpus_identity_profile($conn,(string)$x['pemilik_tipe'],(int)($x['pemilik_id']??0),$x);$rows[]=[$x['nomor_anggota'],$p['nama'],$p['unit'],$x['judul'],$x['tanggal_kembali'],(float)$x['denda'],(float)$x['diselesaikan'],max(0,(float)$x['denda']-(float)$x['diselesaikan']),$x['denda_status']];}}
elseif($report==='reservasi'){$title='LAPORAN RESERVASI';$headers=['Tanggal Reservasi','Nomor Anggota','Nama','Unit/Rombel','Judul','Status','Tanggal Siap','Batas Ambil','Tanggal Selesai','Sumber'];$widths=[22,20,30,24,38,16,22,22,22,16];$text=[1];$data=xrows($conn,"SELECT r.*,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan,b.judul FROM perpus_reservasi r JOIN perpus_anggota a ON a.id=r.anggota_id JOIN perpus_buku b ON b.id=r.buku_id WHERE DATE(r.tanggal_reservasi) BETWEEN ? AND ? ORDER BY r.tanggal_reservasi DESC",'ss',[$from,$to]);foreach($data as $x){$p=sds_perpus_identity_profile($conn,(string)$x['pemilik_tipe'],(int)($x['pemilik_id']??0),$x);$rows[]=[$x['tanggal_reservasi'],$x['nomor_anggota'],$p['nama'],$p['unit'],$x['judul'],$x['status'],$x['tanggal_siap'],$x['batas_ambil'],$x['tanggal_selesai'],$x['sumber']];}}
else{$title='LAPORAN KRITIK DAN SARAN';$headers=['Waktu','Pengirim','Nomor Anggota/Kontak','Kategori','Judul','Pesan','Status','Tanggapan'];$widths=[22,30,24,16,30,50,16,50];$text=[2];$data=xrows($conn,"SELECT s.*,a.nomor_anggota,a.pemilik_tipe,a.pemilik_id,a.legacy_nama,a.legacy_nis,a.legacy_kelas,a.legacy_jurusan FROM perpus_saran s LEFT JOIN perpus_anggota a ON a.id=s.anggota_id WHERE DATE(s.created_at) BETWEEN ? AND ? ORDER BY s.created_at DESC",'ss',[$from,$to]);foreach($data as $x){$p=!empty($x['anggota_id'])?sds_perpus_identity_profile($conn,(string)$x['pemilik_tipe'],(int)($x['pemilik_id']??0),$x):['nama'=>$x['nama_pengirim']?:'Anonim'];$rows[]=[$x['created_at'],$p['nama'],$x['nomor_anggota']?:$x['kontak'],$x['kategori'],$x['judul'],$x['pesan'],$x['status'],$x['jawaban']];}}
$sheets[]=['name'=>'DATA','title'=>$title,'subtitle'=>$school.' · '.$period,'headers'=>$headers,'rows'=>$rows,'widths'=>$widths,'text_columns'=>$text];
PerpusXlsxLite::download('laporan_perpus_'.$report.'_'.date('Ymd_His').'.xlsx',$sheets);
